/**
 * Signing tests for @orchestkit/hook-contract.
 *
 * Two layers:
 *   1. Vector-driven: every JSON in test-vectors/signing/ is loaded and asserted.
 *      These are the cross-language conformance contract (shared with PyPI sibling).
 *   2. API-level: covers programmer-error throws, sign() round-trip, weak-secret
 *      callback, and key-rotation acceptance.
 */
import { readdirSync, readFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { describe, expect, it, vi } from 'vitest';

import {
  HOOK_SIGNATURE_HEADER,
  type Reason,
  sign,
  verify,
} from '../src/signing.js';

const __dirname = dirname(fileURLToPath(import.meta.url));
const VECTORS_DIR = join(__dirname, '..', 'test-vectors', 'signing');

interface Vector {
  name: string;
  description: string;
  secret_hex: string;
  body_b64: string;
  timestamp: number;
  now: number;
  tolerance_sec: number;
  header: string;
  expected: { valid: boolean; reason: Reason };
}

function loadVectors(): Vector[] {
  return readdirSync(VECTORS_DIR)
    .filter((f) => f.endsWith('.json'))
    .sort()
    .map((f) => JSON.parse(readFileSync(join(VECTORS_DIR, f), 'utf8')) as Vector);
}

describe('signing — golden vectors', () => {
  const vectors = loadVectors();

  it('loads at least the 13 required vectors', () => {
    expect(vectors.length).toBeGreaterThanOrEqual(13);
  });

  it.each(vectors.map((v) => [v.name, v]))(
    'vector: %s',
    (_name, vector) => {
      const v = vector as Vector;
      const secret = Buffer.from(v.secret_hex, 'hex');
      const body = Buffer.from(v.body_b64, 'base64');
      const header = v.header === '' ? null : v.header;

      const result = verify(header, body, secret, {
        now: v.now,
        toleranceSec: v.tolerance_sec,
      });

      expect(result).toEqual(v.expected);
    },
  );
});

describe('signing — API surface', () => {
  const secret = Buffer.from(
    '00112233445566778899aabbccddeeff00112233445566778899aabbccddeeff',
    'hex',
  );
  const body = Buffer.from('{"event":"PreToolUse"}', 'utf8');

  it('exposes the header name constant', () => {
    expect(HOOK_SIGNATURE_HEADER).toBe('X-CC-Hooks-Signature');
  });

  it('sign() + verify() round-trip succeeds', () => {
    const t = 1_731_000_000;
    const header = sign(body, secret, { timestamp: t });
    expect(header).toMatch(/^t=1731000000,v1=[0-9a-f]{64}$/);

    const result = verify(header, body, secret, { now: t });
    expect(result).toEqual({ valid: true, reason: 'ok' });
  });

  it('verify() returns missing_header on null/undefined/empty', () => {
    expect(verify(null, body, secret).reason).toBe('missing_header');
    expect(verify(undefined, body, secret).reason).toBe('missing_header');
    expect(verify('', body, secret).reason).toBe('missing_header');
  });

  it('verify() never throws on malformed input — maps to reason', () => {
    const t = 1_731_000_000;
    const bad = [
      '',
      ',',
      '=',
      't=,v1=abc',
      't=abc,v1=abc',
      't=1731000000,v1=', // empty digest
      't=1731000000,v1=zzzz', // non-hex, also too short
      't=1731000000,t=1731000000,v1=' + 'a'.repeat(64), // duplicate t
      't=1731000000,v1=' + 'a'.repeat(64) + ',v1=' + 'b'.repeat(64), // duplicate scheme
      't=1731000000,unknown=' + 'a'.repeat(64), // unknown key
      ' t=1731000000,v1=' + 'a'.repeat(64), // leading whitespace
    ];
    for (const header of bad) {
      const result = verify(header, body, secret, { now: t });
      expect(result.valid).toBe(false);
      expect(['malformed_header', 'missing_header', 'signature_mismatch']).toContain(result.reason);
    }
  });

  it('sign() throws on invalid timestamp or scheme', () => {
    expect(() => sign(body, secret, { timestamp: -1 })).toThrow(/non-negative/);
    expect(() => sign(body, secret, { timestamp: 1.5 })).toThrow(/non-negative/);
    expect(() => sign(body, secret, { scheme: 'v' })).toThrow(/scheme/);
    expect(() => sign(body, secret, { scheme: 'V1' })).toThrow(/scheme/);
  });

  it('verify() throws on programmer errors', () => {
    expect(() => verify('t=1,v1=' + 'a'.repeat(64), 'not-bytes' as unknown as Uint8Array, secret)).toThrow(
      /Uint8Array/,
    );
    // @ts-expect-error — exercising null secret
    expect(() => verify('t=1,v1=' + 'a'.repeat(64), body, null)).toThrow(/secret/);
  });

  it('accepts a key-rotation array of secrets — any match passes', () => {
    const t = 1_731_000_000;
    const oldSecret = Buffer.alloc(32, 0xaa);
    const newSecret = Buffer.alloc(32, 0xbb);
    const headerOld = sign(body, oldSecret, { timestamp: t });

    // Verifier configured with [new, old] — old secret signature still accepted
    const result = verify(headerOld, body, [newSecret, oldSecret], { now: t });
    expect(result).toEqual({ valid: true, reason: 'ok' });
  });

  it('emits weak_secret warning when secret is shorter than 32 bytes', () => {
    const onWarning = vi.fn();
    const shortSecret = Buffer.alloc(16, 0xaa);
    const header = sign(body, shortSecret, { timestamp: 1_731_000_000 });
    const result = verify(header, body, shortSecret, {
      now: 1_731_000_000,
      onWarning,
    });

    expect(result).toEqual({ valid: true, reason: 'ok' });
    expect(onWarning).toHaveBeenCalledWith('weak_secret');
  });

  it('does NOT emit weak_secret when all secrets are ≥ 32 bytes', () => {
    const onWarning = vi.fn();
    verify(sign(body, secret), body, secret, { onWarning });
    expect(onWarning).not.toHaveBeenCalled();
  });

  it('rejects oversized headers as malformed (DoS cap at 8192 bytes)', () => {
    const t = 1_731_000_000;
    // Build a header just past the 8192-byte cap by padding with extra (parseable) schemes.
    const fakeScheme = (n: number) => `v${n}=${'a'.repeat(64)}`;
    let header = `t=${t}`;
    let i = 100;
    while (header.length <= 8192) {
      header += `,${fakeScheme(i++)}`;
    }
    expect(header.length).toBeGreaterThan(8192);

    const result = verify(header, body, secret, { now: t });
    expect(result).toEqual({ valid: false, reason: 'malformed_header' });
  });

  it('rejects timestamps with more than 10 digits as stale', () => {
    const tooLong = '1' + '0'.repeat(15); // 16 digits, well past year 2286
    const result = verify(`t=${tooLong},v1=${'a'.repeat(64)}`, body, secret);
    expect(result).toEqual({ valid: false, reason: 'stale' });
  });

  it('does not fire weak_secret when header is malformed (info disclosure tightening)', () => {
    const onWarning = vi.fn();
    const shortSecret = Buffer.alloc(16, 0xaa);
    verify('garbage', body, shortSecret, { onWarning });
    expect(onWarning).not.toHaveBeenCalled();
  });

  it('multi-scheme header: only the matching scheme needs to verify', () => {
    const t = 1_731_000_000;
    const secretA = Buffer.alloc(32, 0xaa);
    const secretB = Buffer.alloc(32, 0xbb);
    // Construct a header where v1 is signed with A and v2 is signed with B.
    const hA = sign(body, secretA, { timestamp: t, scheme: 'v1' });
    const hB = sign(body, secretB, { timestamp: t, scheme: 'v2' });
    // Combine: t=...,v1=<A>,v2=<B>
    const combined = `${hA},${hB.split(',')[1]}`;

    // Verifier holds only B → v2 matches.
    expect(verify(combined, body, secretB, { now: t })).toEqual({
      valid: true,
      reason: 'ok',
    });
    // Verifier holds only A → v1 matches.
    expect(verify(combined, body, secretA, { now: t })).toEqual({
      valid: true,
      reason: 'ok',
    });
  });
});
